CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`content`.`sports_event` (
    `sports_event_id` BIGINT COMMENT 'Primary key for the sports event entity',
    `primary_home_sports_team_id` BIGINT COMMENT 'Alternate FK to the home sports team',
    `sports_away_team_id` BIGINT COMMENT 'FK to the away team',
    `sports_competition_id` BIGINT COMMENT 'FK to the competition/tournament this event belongs to',
    `series_id` BIGINT COMMENT 'Alternate FK to content series',
    `sports_series_id` BIGINT COMMENT 'FK to the content series this event belongs to',
    `sports_team_id` BIGINT COMMENT 'FK to the home team',
    `title_id` BIGINT COMMENT 'FK to the content title representing this event',
    `actual_end_timestamp` TIMESTAMP COMMENT 'Actual end timestamp of the event',
    `actual_start_at` TIMESTAMP COMMENT 'Actual start timestamp',
    `actual_start_timestamp` TIMESTAMP COMMENT 'Alternate actual start timestamp field',
    `attendance` STRING COMMENT 'Number of attendees at the event',
    `away_score` STRING COMMENT 'Final score for the away team',
    `away_team` STRING COMMENT 'Denormalized away team name',
    `blackout_flag` BOOLEAN COMMENT 'Whether the event is subject to blackout restrictions',
    `competition_name` STRING COMMENT 'Name of the competition or tournament',
    `created_at` TIMESTAMP COMMENT 'Timestamp when the record was created',
    `event_date` DATE COMMENT 'Date of the event',
    `event_name` STRING COMMENT 'Name of the sports event (e.g. Super Bowl LVIII)',
    `event_start_timestamp` TIMESTAMP COMMENT 'Generic event start timestamp',
    `event_status` STRING COMMENT 'Current status (scheduled, in_progress, completed, postponed, cancelled)',
    `home_score` STRING COMMENT 'Final score for the home team',
    `home_team` STRING COMMENT 'Denormalized home team name',
    `is_live_flag` BOOLEAN COMMENT 'Whether the event is broadcast live',
    `league_name` STRING COMMENT 'Denormalized league name',
    `scheduled_start_at` TIMESTAMP COMMENT 'Scheduled start timestamp',
    `scheduled_start_timestamp` TIMESTAMP COMMENT 'Alternate scheduled start timestamp field',
    `season_label` STRING COMMENT 'Season identifier (e.g. 2024-25)',
    `source_system_code` STRING COMMENT 'Identifier in the source system',
    `sport_type` STRING COMMENT 'Type of sport for this event',
    `updated_at` TIMESTAMP COMMENT 'Timestamp when the record was last updated',
    `venue_city` STRING COMMENT 'City of the venue',
    `venue_country` STRING COMMENT 'Country of the venue',
    `venue_name` STRING COMMENT 'Name of the venue where the event takes place',
    CONSTRAINT pk_sports_event PRIMARY KEY(`sports_event_id`)
) COMMENT 'Game/match per-event metadata: home/away teams, venue, season, date, status, broadcast window';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`content`.`sports_team` (
