CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`content`.`news_story` (
    `news_story_id` BIGINT COMMENT 'Surrogate primary key for the news story.',
    `title_id` BIGINT COMMENT 'FK to the related content title, if the story is published as a title.',
    `byline` STRING COMMENT 'Reporter/author byline credited on the story (Schema.org NewsArticle author). PII person name.',
    `correction_flag` BOOLEAN COMMENT 'Whether a correction has been issued against this story.',
    `correction_note` STRING COMMENT 'Editors note / text of the published correction or retraction.',
    `correction_status` STRING COMMENT 'Correction lifecycle state (none, pending, corrected, retracted) for the story.',
    `created_at` TIMESTAMP COMMENT 'Lineage: record creation timestamp.',
    `dateline` STRING COMMENT 'Place and date of origin of the story (e.g. WASHINGTON, May 27).',
    `editorial_workflow_state` STRING COMMENT 'Workflow state: draft, assigned, filed, edited, cleared, published.',
    `embargo_flag` BOOLEAN COMMENT 'Whether the story is under embargo and may not be published before the embargo time.',
    `embargo_until_timestamp` TIMESTAMP COMMENT 'Timestamp until which the story is embargoed from publication.',
    `filed_at` TIMESTAMP COMMENT 'Timestamp the reporter filed the story to the editorial desk.',
    `headline` STRING COMMENT 'Story headline (Schema.org NewsArticle headline).',
    `primary_language` STRING COMMENT 'ISO language code of the story content.',
    `published_at` TIMESTAMP COMMENT 'Timestamp the story was published (Schema.org datePublished).',
    `section` STRING COMMENT 'Editorial section (politics, business, sports, world) - Schema.org articleSection.',
    `source_system_code` STRING COMMENT 'Lineage: identifier of the record in the source system.',
    `story_slug` STRING COMMENT 'Short URL-friendly identifier/slug for the news story (Schema.org NewsArticle url/identifier).',
    `story_status` STRING COMMENT 'Overall status of the story (draft, published, killed, updated).',
    `updated_at` TIMESTAMP COMMENT 'Lineage: record last-update timestamp (Schema.org dateModified).',
    `wire_source` STRING COMMENT 'Originating news agency / wire source (AP, AFP, Bloomberg, Reuters) per NewsMediaOrganization.',
    `word_count` STRING COMMENT 'Approximate word count of the story body (Schema.org wordCount).',
    CONSTRAINT pk_news_story PRIMARY KEY(`news_story_id`)
) COMMENT 'News story / article in the newsroom subdomain, aligned with Schema.org NewsArticle and NewsMediaOrganization; captures story slug, dateline, byline, wire source, embargo, correction lifecycle, and editorial workflow state.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`content`.`podcast_dynamic_ad_insertion` (
