CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`content`.`wire_ingest` (
    `wire_ingest_id` BIGINT COMMENT 'Primary key.',
    `news_story_id` BIGINT COMMENT 'FK to the news_story created from this wire ingest.',
