    `priority` STRING COMMENT 'Wire priority level (flash/urgent/routine).',
    `processing_status` STRING COMMENT 'Status: received, parsed, assigned, rejected.',
    `raw_content` STRING COMMENT 'Raw text/XML content as received from the wire.',
    `source_system_code` STRING COMMENT 'Lineage: source record identifier.',
