    CONSTRAINT pk_wire_ingest PRIMARY KEY(`wire_ingest_id`)
) COMMENT 'Inbound feed from news agencies (AP, AFP, Bloomberg) capturing raw wire content into the editorial workflow.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`content`.`byline_credit` (
