CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`content`.`content_correction_record` (
    `content_correction_record_id` BIGINT COMMENT 'Primary key.',
    `news_story_id` BIGINT COMMENT 'FK to the news story being corrected.',
    `approved_by_name` STRING COMMENT 'Name of the editor/legal who approved the correction.',
    `compliance_reference` STRING COMMENT 'Reference to the compliance filing or regulatory case number.',
    `correction_text` STRING COMMENT 'Full text of the correction or retraction.',
