    `reason` STRING COMMENT 'Reason for the correction (factual error, legal, regulatory mandate).',
    `regulatory_mandate_flag` BOOLEAN COMMENT 'Whether this correction was mandated by a regulator (FCC/Ofcom).',
    `severity` STRING COMMENT 'Severity level: minor, major, critical.',
    `source_system_code` STRING COMMENT 'Lineage: source record identifier.',
    `updated_at` TIMESTAMP COMMENT 'Lineage: row update timestamp.',
    CONSTRAINT pk_content_correction_record PRIMARY KEY(`content_correction_record_id`)
) COMMENT 'Editors note, retraction, or FCC/Ofcom-mandated on-air correction linked to a news story. Supports compliance audit trail.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`content`.`breaking_news_event` (
    `breaking_news_event_id` BIGINT COMMENT 'Primary key.',
    `news_story_id` BIGINT COMMENT 'FK to the associated news story.',
    `title_id` BIGINT COMMENT 'FK to the content title if a special report title is created.',
    `affected_channels` STRING COMMENT 'Comma-separated list of channel IDs affected by the crash-out.',
    `anchor_name` STRING COMMENT 'Name of the anchor covering the breaking event.',
    `created_at` TIMESTAMP COMMENT 'Lineage: row creation timestamp.',
    `created_timestamp` TIMESTAMP COMMENT 'Record creation timestamp.',
    `end_datetime` TIMESTAMP COMMENT 'When the breaking coverage ended and normal programming resumed.',
