    `geographic_scope` STRING COMMENT 'Geographic scope of the event: local, national, global.',
    `is_active_flag` BOOLEAN COMMENT 'Whether the breaking event is currently active.',
    `preempted_program` STRING COMMENT 'Name/ID of the program that was preempted.',
    `severity_level` STRING COMMENT 'Severity: flash, bulletin, special_report.',
    `source_system_code` STRING COMMENT 'Lineage: source record identifier.',
    `trigger_datetime` TIMESTAMP COMMENT 'When the breaking news event was triggered.',
    `updated_at` TIMESTAMP COMMENT 'Lineage: row update timestamp.',
    CONSTRAINT pk_breaking_news_event PRIMARY KEY(`breaking_news_event_id`)
) COMMENT 'Crash-out/special-report trigger that feeds program_rundown for breaking news interruptions of scheduled programming.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`content`.`editorial_workflow_state` (
    `editorial_workflow_state_id` BIGINT COMMENT 'Primary key.',
    `content_episode_id` BIGINT COMMENT '',
    `active_flag` BOOLEAN COMMENT 'Whether this state is currently active in the system.',
    `created_at` TIMESTAMP COMMENT 'Lineage: row creation timestamp.',
