    `state_description` STRING COMMENT 'Description of what this state means in the editorial process.',
    `state_label` STRING COMMENT 'Human-readable label for the workflow state.',
    `updated_at` TIMESTAMP COMMENT 'Lineage: row update timestamp.',
    CONSTRAINT pk_editorial_workflow_state PRIMARY KEY(`editorial_workflow_state_id`)
) COMMENT 'Reference table for editorial workflow states: draft, assigned, filed, edited, cleared, published, killed.';

